import { DatePipe } from "@angular/common";
import { Component, OnInit, ViewChild } from "@angular/core";
import { FormBuilder, FormGroup, Validators } from "@angular/forms";
import { IonCheckbox } from "@ionic/angular";
import { startOfDay, startOfMonth } from "date-fns";
import { AlertService } from "src/app/core/services/alert.service";
import { BankService } from "src/app/core/services/bank.service";
import { LoansService } from "src/app/core/services/loans.service";
import { pagingService } from "src/app/core/services/paging.service";
import { ReferencesService } from "src/app/core/services/references.service";
import { sortingService } from "src/app/core/services/sorting.service";
import * as customValidators from "src/app/core/validators/custom-validators";
import { BranchBanks } from "src/app/views/Models/Banks/BranchBanks";
import { IClientType } from "src/app/views/Models/Client/ClientType";
import { ChangeBankForUndisbLoansRequest } from "src/app/views/Models/Loan/ChangeBankForUndisbLoansRequest";
import { ChangeBankUndisbLoans } from "src/app/views/Models/Loan/ChangeBankUndisbLoans";
import { ChangeBankUndisbLoansRequest } from "src/app/views/Models/Loan/ChangeBankUndisbLoansRequest";
import { IBranch } from "src/app/views/Models/References/Branch";
import { StaticRef } from "src/app/views/Models/References/StaticRef";

@Component({
  selector: "app-change-bank",
  templateUrl: "./change-bank.page.html",
  styleUrls: ["./change-bank.page.scss"],
})
export class ChangeBankPage implements OnInit {
  @ViewChild("ionCheckBox") ionCheckBox: IonCheckbox;

  //#region Flags
  showLoader: boolean = false;
  isSearchForm: boolean = true;
  isSearchFormSubmitted: boolean = false;
  checkDatesInput: boolean = false;
  banksDisabled: boolean = true;
  isGridForm: boolean = false;
  isChangeBankFormValid: boolean = false;
  selectDisbOption: boolean = false;
  //#endregion

  //#region Variables
  all_applic: number = 0;
  branches: IBranch[];
  banks: BranchBanks[];
  clientTypes: IClientType[];
  disbMethods: StaticRef[];
  UndisbLoanRequest: ChangeBankUndisbLoansRequest;
  undisbLoans: Array<ChangeBankUndisbLoans & { isChecked: boolean }>;
  selectedLoans: any[] = [];
  page: number = 1;
  sortingIconClass: string;
  sortingIconParam: string;
  cashout_code: number;
  //#endregion

  //#region Forms
  searchForm: FormGroup = this.formBuilder.group({
    branchCode: ["", Validators.required],
    bankCodes: [
      { value: null, disabled: this.banksDisabled },
      Validators.required,
    ],
    clientTypeCode: ["", Validators.required],
    loanDateFrom: [
      startOfMonth(new Date()),
      customValidators.dateTypeStringValidator({
        required: true,
      }),
    ],
    loanDateTo: [
      startOfDay(new Date()),
      customValidators.dateTypeStringValidator({
        required: true,
      }),
    ],
  });
  changeBankForm: FormGroup = this.formBuilder.group({
    bankCode: ["", Validators.required],
    disbMethod: ["", Validators.required],
  });
  //#endregion

  //#region Initialize
  constructor(
    private formBuilder: FormBuilder,
    private referencesService: ReferencesService,
    private bankService: BankService,
    private loansService: LoansService,
    private alertService: AlertService,
    private datePipe: DatePipe,
    public pagingService: pagingService,
    private sortingService: sortingService
  ) {}

  async ngOnInit() {
    this.branches = await this.referencesService.GetbranchByUser();
    this.clientTypes = await this.referencesService.GetClientTypes();
    this.disbMethods = (await this.referencesService.getDisbMethods()).filter(
      (x) => x.ref_code !== "3"
    );
  }
  async getBanksByBranches(ev: any) {
    let branch_code = ev.detail.value;
    if (branch_code) {
      this.showLoader = true;
      this.searchForm.controls.bankCodes.reset();
      this.banks = await this.bankService.getBranchBanks(branch_code);
      if (this.banks) {
        this.banksDisabled = this.banks.length > 0 ? false : true;
        if (this.banksDisabled) {
          this.searchForm.controls.bankCodes.disable();
          this.banks = null;
        } else {
          this.searchForm.controls.bankCodes.enable();
        }
      }
      this.showLoader = false;
    }
  }
  //#endregion

  //#region Search
  async getUndisbLoans() {
    this.isSearchFormSubmitted = true;
    if (this.searchForm.valid) {
      if (!this.searchForm.controls.bankCodes.value) {
        await this.alertService.showAlertError("يجب اختيار البنك", false);
        return;
      }
      try {
        this.showLoader = true;
        this.undisbLoans = null;
        this.UndisbLoanRequest = {
          branch_code: Number(this.searchForm.controls.branchCode.value),
          client_type_code:
            this.searchForm.controls.clientTypeCode.value.toString(),
          bank_codes: this.searchForm.controls.bankCodes.value.toString(),
          loan_date_start: new Date(
            this.searchForm.controls.loanDateFrom.value
          ),
          loan_date_end: new Date(this.searchForm.controls.loanDateTo.value),
        };
        this.undisbLoans = await (
          await this.loansService.getChangeBankUndisbLoans(
            this.UndisbLoanRequest
          )
        ).map((x) => ({
          ...x,
          isChecked: false,
        }));
        if (this.undisbLoans.length > 0) {
          this.showLoader = false;
          this.isGridForm = true;
          this.isSearchForm = false;
        } else {
          this.showLoader = false;
          this.alertService.InfoAlert("لا يوجد قروض", false);
        }
      } catch (err) {
        this.showLoader = false;
        this.alertService.showAlertError(err.message, false);
        console.log(err);
      }
    }
  }

  backtoSearchForm() {
    this.isSearchForm = true;
    this.isGridForm = false;
    this.undisbLoans = null;
    this.page = 1;
    this.selectedLoans = [];
    this.cashout_code = null;
    this.changeBankForm.reset();
    this.isChangeBankFormValid = false;
    this.selectDisbOption = false;
  }
  changePage(newPage: number): void {
    this.page = newPage;
  }
  sortingTable(data: any, param: string) {
    this.sortingService.sortByParameter(data, param);
    this.sortingIconClass =
      this.sortingService.sortOrder === "asc"
        ? "arrow-down-outline"
        : "arrow-up-outline";
    this.sortingIconParam = param;
  }
  //#endregion

  //#region Checkbox
  set isAllSelected(value: boolean) {
    this.undisbLoans.forEach((app) => (app.isChecked = value));
  }
  onCheckboxMasterChange(event: any) {
    const isChecked = event.target.checked;
    this.undisbLoans.forEach((x) => (x.isChecked = isChecked));
    this.updateSelectedLoanForAll(isChecked);
  }
  updateSelectedLoanForAll(isChecked: boolean) {
    this.selectedLoans = [];
    if (isChecked) {
      this.undisbLoans.forEach((x) => {
        this.selectedLoans.push(x.loan_key);
      });
      this.all_applic = 1;
    }
  }
  convertStringToDate(str: string) {
    let date = new Date(str);
    return date.toLocaleDateString();
  }
  onCheckboxChange(event: any, app_key: any, index: any) {
    const selectedApp =
      this.undisbLoans[index + this.pagingService.pageSize * (this.page - 1)];

    selectedApp.isChecked = event.target.checked;
    this.updateSelectedApplicaiton(app_key, event.target.checked);
    this.updateMasterCheckbox();
    if (this.undisbLoans.length !== this.selectedLoans.length) {
      if (this.selectedLoans.length === 0) {
        this.ionCheckBox.indeterminate = false;
      } else {
        this.ionCheckBox.indeterminate = true;
      }
      this.all_applic = 0;
    } else if (this.undisbLoans.length === this.selectedLoans.length) {
      this.ionCheckBox.indeterminate = false;
      this.isAllSelected = true;
      this.all_applic = 1;
    }
  }
  updateSelectedApplicaiton(loan_key: any, isChecked: boolean) {
    const index = this.selectedLoans.indexOf(loan_key);
    if (isChecked && index === -1) {
      this.selectedLoans.push(loan_key);
    } else if (!isChecked && index > -1) {
      this.selectedLoans.splice(index, 1);
    }
  }
  updateMasterCheckbox() {
    const allSelected = this.undisbLoans.every((x) => x.isChecked);
    const someSelected = this.undisbLoans.some((x) => x.isChecked);

    if (allSelected) {
      this.isAllSelected = true;
      this.ionCheckBox.checked = true;
    } else if (!someSelected) {
      this.ionCheckBox.checked = false;
      this.ionCheckBox.indeterminate = false;
      this.isAllSelected = false;
      this.all_applic = 0;
    }
  }
  //#endregion

  //#region ChangeBank
  selectBank(ev: any) {
    let curBank = ev.target.value;
    this.cashout_code = this.banks.find(
      (x) => x.bank_code === curBank
    ).cashout_code;
    if (!this.cashout_code) {
      this.selectDisbOption = true;
      this.changeBankForm.controls.disbMethod.reset();
    } else {
      this.selectDisbOption = false;
      this.changeBankForm.patchValue({
        disbMethod: "3",
      });
    }
  }

  async submitChangeBanks() {
    this.isChangeBankFormValid = true;
    if (this.changeBankForm.valid) {
      if (await this.alertService.SaveAlert("هل انت متاكد من تغيير البنك؟")) {
        try {
          this.showLoader = true;
          let request: ChangeBankForUndisbLoansRequest = {
            branch_code: Number(this.searchForm.controls.branchCode.value),
            loan_keys: this.selectedLoans.toString(),
            bank_code: Number(this.changeBankForm.controls.bankCode.value),
            disb_method: Number(this.changeBankForm.controls.disbMethod.value),
          };
          await this.loansService.changeBankForUndisbLoans(request);
          await this.alertService.showAlertConfirm(
            "تم تعديل البنك بنجاح",
            false
          );
          this.backtoSearchForm();
          this.searchForm.controls.branchCode.reset();
          this.searchForm.controls.bankCodes.reset();
          this.searchForm.controls.clientTypeCode.reset();
          this.banks = null;
          this.searchForm.controls.bankCodes.disable();
          this.isSearchFormSubmitted = false;
          this.showLoader = false;
        } catch (err) {
          await this.alertService.showAlertError(err.error, false);
          this.showLoader = false;
        }
      }
    }
  }
  //#endregion
}
